from flask import Flask, jsonify
import time
from datetime import datetime

app = Flask(__name__)

def api():
    with open('app/data/api.json') as f:
        return json.loads(f.read())['url']

@app.route('/api', methods=['GET'])
def mainAPI():

    #get the timestamp of api
    ts = api()
    #convert the timestamp to datetime object for expiry
    expire = dt.strptime(ts,'%Y-%m-%d %H:%M:%S.%f')
    
    if (dt.now()>expire): #if the timestamp is greater than or equal to 1 hr old,
        delData() #delete the file, and run api to update it again

    with open('app/data/api.json') as f:
            return jsonify(json.loads(f.read()))
    

def delData():
    os.remove("app/data/api.json")
    ts = api()
    expire = dt.strptime(ts,'%Y-%m-%d %H:%M:%S.%f')

if __name__ == '__main__':
   app.run()